#include <bits/stdc++.h>
using namespace std;
const int sb=10090;
string s,t;
int a[sb],b[sb],len;
int main(){
    cin>>s;
    len=s.size();
    cin>>t;
    if(len<t.size())len=t.size();
    if((t.size()>s.size()) || (t.size()==s.size() && t>s)){
    	swap(s,t);
    	cout<<'-';
	}
	else if(t==s){
		cout<<0;
		return 0;
	}
	for(int i=len;i>=1;i--){
        a[i]=s[len-i]-'0';
    }
	for(int i=1;i<=t.size();i++){
        b[i]=t[t.size()-i]-'0';
    }
    for(int i=1;i<=len;i++){
    	a[i]=a[i]-b[i];
    	if(a[i]<0){
    		a[i+1]-=1;
    		a[i]+=10;
		}
	}
	while(a[len]==0)len--;
	for(int i=len;i>0;i--)cout<<a[i];
    return 0;
}
